```ts
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { NextResponse } from "next/server";

export async function GET() {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const memberships = await prisma.teamMember.findMany({
    where: { userId: session.user.id },
    include: { team: true },
  });

  return NextResponse.json(memberships.map((m) => ({ ...m.team, role: m.role })));
}

export async function POST(req: Request) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const { name } = await req.json();
  if (!name?.trim()) return NextResponse.json({ error: "Name required" }, { status: 400 });

  const team = await prisma.team.create({
    data: {
      name: name.trim(),
      members: {
        create: { userId: session.user.id, role: "ADMIN" },
      },
    },
  });

  return NextResponse.json(team);
}
```

**`src/app/api/notes/route.ts`** (create + list for a team)
```ts
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { NextResponse } from "next/server";

export async function GET(req: Request) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const { searchParams } = new URL(req.url);
  const teamId = searchParams.get("teamId");
  if (!teamId) return NextResponse.json({ error: "teamId required" }, { status: 400 });

  // Security check: is user a member?
  const membership = await prisma.teamMember.findUnique({
    where: { userId_teamId: { userId: session.user.id, teamId } },
  });
  if (!membership) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  const notes = await prisma.note.findMany({
    where: { teamId },
    include: { author: { select: { name: true } } },
    orderBy: { updatedAt: "desc" },
  });

  return NextResponse.json(notes);
}

export async function POST(req: Request) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const { title, content = "", teamId } = await req.json();
  if (!title?.trim() || !teamId) {
    return NextResponse.json({ error: "title and teamId required" }, { status: 400 });
  }

  const membership = await prisma.teamMember.findUnique({
    where: { userId_teamId: { userId: session.user.id, teamId } },
  });
  if (!membership) return NextResponse.json({ error: "Forbidden" }, { status: 403 });

  const note = await prisma.note.create({
    data: {
      title: title.trim(),
      content,
      teamId,
      authorId: session.user.id,
    },
    include: { author: { select: { name: true } } },
  });

  return NextResponse.json(note);
}
```

**`src/app/api/notes/[id]/route.ts`** (get / update / delete)
```ts
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { NextResponse } from "next/server";

async function checkAccess(userId: string, noteId: string) {
  const note = await prisma.note.findUnique({
    where: { id: noteId },
    include: { team: { include: { members: true } } },
  });
  if (!note) return null;
  const isMember = note.team.members.some((m) => m.userId === userId);
  return isMember ? note : null;
}

export async function GET(_: Request, { params }: { params: { id: string } }) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const note = await checkAccess(session.user.id, params.id);
  if (!note) return NextResponse.json({ error: "Not found or forbidden" }, { status: 404 });

  return NextResponse.json(note);
}

export async function PATCH(req: Request, { params }: { params: { id: string } }) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const note = await checkAccess(session.user.id, params.id);
  if (!note) return NextResponse.json({ error: "Not found or forbidden" }, { status: 404 });

  const body = await req.json();
  const updated = await prisma.note.update({
    where: { id: params.id },
    data: {
      title: body.title?.trim() ?? note.title,
      content: body.content ?? note.content,
    },
    include: { author: { select: { name: true } } },
  });

  return NextResponse.json(updated);
}

export async function DELETE(_: Request, { params }: { params: { id: string } }) {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const note = await checkAccess(session.user.id, params.id);
  if (!note) return NextResponse.json({ error: "Not found or forbidden" }, { status: 404 });

  await prisma.note.delete({ where: { id: params.id } });
  return NextResponse.json({ success: true });
}
```

