### `server/middleware/auth.js`
```js
const jwt = require('jsonwebtoken');
const SECRET = process.env.JWT_SECRET || 'dev-secret-change-me';

function auth(req, res, next) {
  const header = req.headers.authorization;
  if (!header) return res.status(401).json({ error: 'No token' });
  try {
    const token = header.split(' ')[1];
    const payload = jwt.verify(token, SECRET);
    req.user = payload;
    next();
  } catch (e) {
    res.status(401).json({ error: 'Invalid token' });
  }
}

module.exports = { auth, SECRET };
```

### `server/routes/auth.js`
```js
const express = require('express');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const db = require('../db');
const { SECRET } = require('../middleware/auth');

const router = express.Router();

// Create a new team + first user (admin)
router.post('/register-team', (req, res) => {
  const { teamName, name, email, password } = req.body;
  if (!teamName || !name || !email || !password)
    return res.status(400).json({ error: 'Missing fields' });

  const inviteCode = crypto.randomBytes(4).toString('hex');
  const team = db.prepare('INSERT INTO teams (name, invite_code) VALUES (?, ?)').run(teamName, inviteCode);

  const hash = bcrypt.hashSync(password, 10);
  const user = db.prepare(
    'INSERT INTO users (name, email, password, team_id) VALUES (?, ?, ?, ?)'
  ).run(name, email, hash, team.lastInsertRowid);

  const token = jwt.sign(
    { id: user.lastInsertRowid, name, email, teamId: team.lastInsertRowid },
    SECRET, { expiresIn: '7d' }
  );

  res.json({ token, inviteCode });
});

// Join existing team via invite code
router.post('/join-team', (req, res) => {
  const { inviteCode, name, email, password } = req.body;
  const team = db.prepare('SELECT * FROM teams WHERE invite_code = ?').get(inviteCode);
  if (!team) return res.status(404).json({ error: 'Invalid invite code' });

  const hash = bcrypt.hashSync(password, 10);
  const user = db.prepare(
    'INSERT INTO users (name, email, password, team_id) VALUES (?, ?, ?, ?)'
  ).run(name, email, hash, team.id);

  const token = jwt.sign(
    { id: user.lastInsertRowid, name, email, teamId: team.id },
    SECRET, { expiresIn: '7d' }
  );

  res.json({ token });
});

router.post('/login', (req, res) => {
  const { email, password } = req.body;
  const user = db.prepare('SELECT * FROM users WHERE email = ?').get(email);
  if (!user || !bcrypt.compareSync(password, user.password))
    return res.status(401).json({ error: 'Invalid credentials' });

  const token = jwt.sign(
    { id: user.id, name: user.name, email: user.email, teamId: user.team_id },
    SECRET, { expiresIn: '7d' }
  );
  res.json({ token });
});

module.exports = router;
```

### `server/routes/notes.js`
```js
const express = require('express');
const db = require('../db');
const { auth } = require('../middleware/auth');
const router = express.Router();

router.use(auth);

// Folders
router.get('/folders', (req, res) => {
  const folders = db.prepare('SELECT * FROM folders WHERE team_id = ? ORDER BY created_at').all(req.user.teamId);
  res.json(folders);
});

router.post('/folders', (req, res) => {
  const { name } = req.body;
  const result = db.prepare('INSERT INTO folders (team_id, name) VALUES (?, ?)').run(req.user.teamId, name);
  res.json({ id: result.lastInsertRowid, name });
});

// Notes list (with optional search/filter)
router.get('/', (req, res) => {
  const { q, folderId, tag } = req.query;
  let sql = `SELECT notes.*, u.name as author_name FROM notes
             JOIN users u ON u.id = notes.created_by
             WHERE notes.team_id = ?`;
  const params = [req.user.teamId];

  if (folderId) { sql += ' AND folder_id = ?'; params.push(folderId); }
  if (q) { sql += ' AND (title LIKE ? OR content LIKE ?)'; params.push(`%${q}%`, `%${q}%`); }
  if (tag) { sql += ' AND tags LIKE ?'; params.push(`%${tag}%`); }

  sql += ' ORDER BY updated_at DESC';
  res.json(db.prepare(sql).all(...params));
});

router.get('/:id', (req, res) => {
  const note = db.prepare('SELECT * FROM notes WHERE id = ? AND team_id = ?')
    .get(req.params.id, req.user.teamId);
  if (!note) return res.status(404).json({ error: 'Not found' });
  res.json(note);
});

router.post('/', (req, res) => {
  const { title, content, folderId, tags } = req.body;
  const result = db.prepare(
    `INSERT INTO notes (team_id, folder_id, title, content, tags, created_by, updated_by)
     VALUES (?, ?, ?, ?, ?, ?, ?)`
  ).run(req.user.teamId, folderId || null, title || 'Untitled', content || '', tags || '', req.user.id, req.user.id);
  res.json({ id: result.lastInsertRowid });
});

router.put('/:id', (req, res) => {
  const { title, content, folderId, tags } = req.body;
  db.prepare(
    `UPDATE notes SET title=?, content=?, folder_id=?, tags=?, updated_by=?, updated_at=CURRENT_TIMESTAMP
     WHERE id=? AND team_id=?`
  ).run(title, content, folderId || null, tags || '', req.user.id, req.params.id, req.user.teamId);
  res.json({ success: true });
});

router.delete('/:id', (req, res) => {
  db.prepare('DELETE FROM notes WHERE id=? AND team_id=?').run(req.params.id, req.user.teamId);
  db.prepare('DELETE FROM comments WHERE note_id=?').run(req.params.id);
  res.json({ success: true });
});

// Comments
router.get('/:id/comments', (req, res) => {
  const comments = db.prepare(
    `SELECT c.*, u.name as author_name FROM comments c
     JOIN users u ON u.id = c.user_id WHERE note_id = ? ORDER BY created_at`
  ).all(req.params.id);
  res.json(comments);
});

router.post('/:id/comments', (req, res) => {
  const { body } = req.body;
  const result = db.prepare(
    'INSERT INTO comments (note_id, user_id, body) VALUES (?, ?, ?)'
  ).run(req.params.id, req.user.id, body);
  res.json({ id: result.lastInsertRowid });
});

module.exports = router;
```

