  <script>
    const timeDisplay = document.getElementById("timeDisplay");
    const modeLabel = document.getElementById("modeLabel");
    const timerNote = document.getElementById("timerNote");
    const timerRing = document.getElementById("timerRing");
    const startResumeBtn = document.getElementById("startResumeBtn");
    const pauseBtn = document.getElementById("pauseBtn");
    const resetBtn = document.getElementById("resetBtn");
    const applySettingsBtn = document.getElementById("applySettingsBtn");
    const workInput = document.getElementById("workInput");
    const breakInput = document.getElementById("breakInput");
    const autoStartInput = document.getElementById("autoStartInput");
    const alertBanner = document.getElementById("alertBanner");

    const STORAGE_KEY = "plain-pomodoro-settings";

    let mode = "work";
    let running = false;
    let timerId = null;
    let endAt = null;

    let workSeconds = 25 * 60;
    let breakSeconds = 5 * 60;
    let remainingSeconds = workSeconds;

    loadSettings();
    resetTimer(false);

    startResumeBtn.addEventListener("click", startOrResume);
    pauseBtn.addEventListener("click", pauseTimer);
    resetBtn.addEventListener("click", () => resetTimer(true));
    applySettingsBtn.addEventListener("click", applySettings);

    function loadSettings() {
      const saved = JSON.parse(localStorage.getItem(STORAGE_KEY) || "{}");

      if (saved.workMinutes) workInput.value = saved.workMinutes;
      if (saved.breakMinutes) breakInput.value = saved.breakMinutes;
      if (typeof saved.autoStart === "boolean") {
        autoStartInput.checked = saved.autoStart;
      }

      workSeconds = sanitizeMinutes(workInput.value) * 60;
      breakSeconds = sanitizeMinutes(breakInput.value) * 60;
      remainingSeconds = workSeconds;
    }

    function saveSettings() {
      localStorage.setItem(
        STORAGE_KEY,
        JSON.stringify({
          workMinutes: sanitizeMinutes(workInput.value),
          breakMinutes: sanitizeMinutes(breakInput.value),
          autoStart: autoStartInput.checked
        })
      );
    }

    function sanitizeMinutes(value) {
      const parsed = Number.parseInt(value, 10);
      if (Number.isNaN(parsed)) return 1;
      return Math.min(Math.max(parsed, 1), 180);
    }

    function applySettings() {
      workInput.value = sanitizeMinutes(workInput.value);
      breakInput.value = sanitizeMinutes(breakInput.value);

      workSeconds = Number(workInput.value) * 60;
      breakSeconds = Number(breakInput.value) * 60;

      saveSettings();
      resetTimer(true);
      showVisualAlert("Settings applied.");
    }

    function startOrResume() {
      if (running) return;

      running = true;
      endAt = Date.now() + remainingSeconds * 1000;

      startResumeBtn.disabled = true;
      pauseBtn.disabled = false;
      timerNote.textContent = "Running";

      timerId = window.setInterval(tick, 250);
      tick();
    }

    function pauseTimer() {
      if (!running) return;

      running = false;
      clearInterval(timerId);

      remainingSeconds = Math.max(0, Math.ceil((endAt - Date.now()) / 1000));

      startResumeBtn.disabled = false;
      startResumeBtn.textContent = "Resume";
      pauseBtn.disabled = true;
      timerNote.textContent = "Paused";

      updateDisplay();
    }

    function resetTimer(showAlert) {
      running = false;
      clearInterval(timerId);

      remainingSeconds = getDurationForMode();

      startResumeBtn.disabled = false;
      startResumeBtn.textContent = "Start";
      pauseBtn.disabled = true;
      timerNote.textContent = "Ready";

      updateDisplay();

      if (showAlert) {
        showVisualAlert("Timer reset.");
      }
    }

    function tick() {
      remainingSeconds = Math.max(0, Math.ceil((endAt - Date.now()) / 1000));
      updateDisplay();

      if (remainingSeconds <= 0) {
        completeInterval();
      }
    }

    function completeInterval() {
      running = false;
